import java.util.Random;

public class Dice {
    private int sides;

    public Dice(int sides) {
        this.sides = sides;
    }

    public int roll() {
        Random rand = new Random();
        return rand.nextInt(sides) + 1;
    }

    public static void main(String[] args) {
        Dice dice = new Dice(6);
        System.out.println("Rolling the dice: " + dice.roll());
    }
}
